const invoices = $input.all();
const now = new Date();

const overdue = invoices.filter(inv => {
  const dueDate = new Date(inv.json.dueDate);
  const daysPastDue = Math.floor((now - dueDate) / (1000 * 60 * 60 * 24));
  return inv.json.status === 'unpaid' && daysPastDue > 0;
}).map(inv => {
  const dueDate = new Date(inv.json.dueDate);
  const daysPastDue = Math.floor((now - dueDate) / (1000 * 60 * 60 * 24));

  // Determine reminder level
  let reminderLevel = 'gentle';
  if (daysPastDue > 30) reminderLevel = 'firm';
  if (daysPastDue > 60) reminderLevel = 'final';

  return {
    json: {
      ...inv.json,
      daysPastDue,
      reminderLevel,
      lastReminder: inv.json.lastReminder || null
    }
  };
});

return overdue;

values.content:
=Write a {{ $json.reminderLevel }} payment reminder email for:

Client: {{ $json.clientName }}
Invoice #: {{ $json.invoiceNumber }}
Amount: ${{ $json.amount }}
Days overdue: {{ $json.daysPastDue }}
Original due date: {{ $json.dueDate }}

Tone guidelines:
- gentle (1-30 days): Friendly reminder, assume they forgot
- firm (31-60 days): Professional but concerned, mention impact
- final (60+ days): Serious, mention next steps (collections, service pause)

Include:
1. Subject line
2. Email body
3. Clear payment instructions
4. Your business name placeholder: [YOUR BUSINESS]

Format as JSON: {"subject": "...", "body": "..."}

parameters.jsCode:
const response = $input.first().json.message.content;
const invoiceData = $('Has Overdue?').first().json;

let email;
try {
  const jsonMatch = response.match(/```json\n?([\s\S]*?)\n?```/);
  const jsonStr = jsonMatch ? jsonMatch[1] : response;
  email = JSON.parse(jsonStr);
} catch (e) {
  email = { subject: 'Payment Reminder', body: response };
}

return [{
  json: {
    to: invoiceData.clientEmail,
    subject: email.subject,
    body: email.body,
    invoiceNumber: invoiceData.invoiceNumber,
    amount: invoiceData.amount,
    daysPastDue: invoiceData.daysPastDue,
    reminderLevel: invoiceData.reminderLevel
  }
}];
